	APPEND(result, "[%i-%i] (", record->id.page, record->id.slot);
	for(i = 0; i < schema->numAttr; i++)
	{
		APPEND_STRING(result, serializeAttr (record, schema, i));
		APPEND(result, "%s", (i == 0) ? "" : ",");
	}
	APPEND_STRING(result, ")");
