#include<stdio.h>
#include<stdlib.h>
#include<sys/stat.h>
#include<sys/types.h>
#include<unistd.h>
#include<string.h>
#include<math.h>
#include "storage_mgr.h"
FILE *pageFile;
 void initStorageManager (void) {
	pageFile = NULL;
}
 RC createPageFile(char *fileName) {
    FILE *file = fopen(fileName, "w+");
    if (file == NULL) {
        return RC_FILE_NOT_FOUND; 
    }
    SM_PageHandle emptyPage = calloc(PAGE_SIZE, 1);
    if (emptyPage == NULL) {
        fclose(file);
        return RC_WRITE_FAILED;
    }
    size_t writeSize = fwrite(emptyPage, sizeof(char), PAGE_SIZE, file);
    free(emptyPage);
    fclose(file);
    if (writeSize < PAGE_SIZE) {
        return RC_WRITE_FAILED;
    }
    return RC_OK;
}
RC openPageFile(char *fileName, SM_FileHandle *fHandle) {
    FILE *fp;
    int File_RC;
    char *pageData;
    int i;
    pageData = (char *) calloc(PAGE_SIZE, sizeof(char));
    if (pageData == NULL) {
        return RC_MEMORY_ALLOCATION_FAIL;
    }
    fp = fopen(fileName, "rb+");
    if (fp == NULL) {
        free(pageData);
        return RC_FILE_NOT_FOUND;
    }
    int DataReadOK = 0;
    for (i = 0; i < 1; i++) {
        File_RC = fread(pageData, PAGE_SIZE, 1, fp);
        if (File_RC == 1) {
            DataReadOK = 1;
            break;
        }
    }
    if (!DataReadOK) {
        free(pageData);
        fclose(fp); 
        return RC_READ_FAILED;
    }
    if (pageData != NULL) {
        fHandle->fileName = fileName;
        fHandle->totalNumPages = atoi(pageData);
        fHandle->curPagePos = 0;
        fHandle->mgmtInfo = fp;
        free(pageData); 
    } else {
        fclose(fp);
        free(pageData); 
        return RC_INVALID_HEADER;
    }
    return RC_OK;
}
RC closePageFile(SM_FileHandle *fHandle) {
    int FILE_RC;
    char *pageData;
    long offset;
    int Action, maxTrial = 1;
    pageData = (char *) calloc(PAGE_SIZE, sizeof(char));
    if (pageData == NULL) {
        return RC_MEMORY_ALLOCATION_FAIL;
    }
    offset = 0;
    FILE_RC = fseek(fHandle->mgmtInfo, offset, SEEK_SET);
    if (FILE_RC != 0) {
        free(pageData);
        return RC_SEEK_FAILED;
    }
    sprintf(pageData, "%d", fHandle->totalNumPages);
    for (Action = 0; Action < maxTrial; Action++) {
        FILE_RC = fwrite(pageData, PAGE_SIZE, 1, fHandle->mgmtInfo);
        if (FILE_RC != 1) {
        free(pageData);
        return RC_WRITE_FAILED;
        } 
        else {

        FILE_RC = fclose(fHandle->mgmtInfo);
        if (FILE_RC != 0) {
            free(pageData);
            return RC_CLOSE_FAILED;
        }
         }
    free(pageData);
    return RC_OK;
    }
}
RC destroyPageFile(char *fileName) {
    int FILE_RC;
    int Trial = 0;
    const int maxTrial = 3; 
    while (Trial < maxTrial) {
        FILE_RC = remove(fileName);
        if (FILE_RC == 0) {
            return RC_OK;
        } else {
            Trial++;
        }
    }
    if (FILE_RC != 0) {
        return RC_DESTROY_FAILED;
    }
    return RC_OK;
}
RC readBlock(int pageNum, SM_FileHandle *fHandle, SM_PageHandle memPage) {
    long offset;
    int FILE_RC;
    int Action, maxTrial = 1; 
    if (pageNum < 0 || pageNum >= fHandle->totalNumPages) {
        return RC_READ_NON_EXISTING_PAGE;
    }
    offset = (pageNum + 1) * PAGE_SIZE;
    FILE_RC = fseek(fHandle->mgmtInfo, offset, SEEK_SET);
    if (FILE_RC != 0) {
        return RC_SEEK_FAILED;
    }
    for (Action = 0; Action < maxTrial; Action++) {
        FILE_RC = fread(memPage, PAGE_SIZE, 1, fHandle->mgmtInfo);
        if (FILE_RC == 1) {
            break;
        }
    }
    if (FILE_RC != 1) {
        return RC_READ_FAILED;
    }
    fHandle->curPagePos = pageNum;
    return RC_OK;
}
RC readFirstBlock(SM_FileHandle *fHandle, SM_PageHandle memPage) {
    int read_code;
    const int maxTrial = 3; 
    int Action = 0;
    for (Action = 0; Action < maxTrial; Action++) {
        read_code = readBlock(0, fHandle, memPage);
        if (read_code == RC_OK) {
            break;
        } else {
            printf("Action %d to read the first block failed. Retrying...\n", Action + 1);
        }
    }
    return read_code;
}
RC readLastBlock(SM_FileHandle *fHandle, SM_PageHandle memPage) {
    int read_code;
    int pageNum;
    const int maxTrial = 3; 
    int Action = 0;
    pageNum = fHandle->totalNumPages - 1;
    if (pageNum < 0) {
        return RC_READ_NON_EXISTING_PAGE;
    }
    for (Action = 0; Action < maxTrial; Action++) {
        read_code = readBlock(pageNum, fHandle, memPage);
        if (read_code == RC_OK) {
            break;
        } 
    }
    return read_code;
}
RC readPreviousBlock(SM_FileHandle *fHandle, SM_PageHandle memPage) {
    int read_code;
    int pageNum;
    const int maxTrial = 2;
    int Action = 0;
    pageNum = fHandle->curPagePos - 1;
    if (pageNum < 0) {
        return RC_READ_NON_EXISTING_PAGE; 
    }
    for (Action = 0; Action < maxTrial; Action++) {
